INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$Projects and Sub-tasks$q$, $q$Organize work into projects, sections, and nested sub-tasks to break large goals into manageable steps.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$Natural-Language Quick Add$q$, $q$Type a task in plain language and Todoist automatically parses due dates, times, priorities, and labels.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$Recurring Due Dates$q$, $q$Set tasks to repeat on flexible schedules, from simple daily recurrences to complex custom patterns.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$Filters and Labels$q$, $q$Create custom filters and apply labels to view tasks across projects by context, priority, or deadline.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$Multiple Views$q$, $q$Switch between list, board (Kanban-style), and calendar layouts to match different working styles.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$Collaboration and Task Assignment$q$, $q$Share projects with others, assign tasks, leave comments, and attach files for team coordination.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$Reminders$q$, $q$Get notified about upcoming or overdue tasks via push notification, email, or SMS on paid plans.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$Templates$q$, $q$Start new projects quickly using built-in or community-shared templates for common workflows.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$Integrations and API$q$, $q$Connect Todoist to calendars, email, and third-party apps like Slack and Zapier, or build custom workflows with the public API.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$Productivity Tracking$q$, $q$Track completed tasks and streaks over time with built-in productivity visualizations.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$Clean, fast interface with a low learning curve for basic task management$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$Strong cross-platform sync across web, desktop, and mobile apps$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$Natural-language quick add makes capturing tasks fast$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$Flexible filters and labels support many personal productivity systems$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$Generous free plan for individuals with light project needs$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$Free plan caps active projects and lacks reminders$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$Lacks advanced project management features like Gantt charts or resource planning$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$Recent price increases have made Pro and Business less competitive against some rivals$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$Limited native reporting and analytics compared to dedicated PM tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$Some advanced features (reminders, templates, automatic backups) are locked behind paid tiers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$Is Todoist free to use?$q$, $q$Yes, Todoist offers a free Beginner plan with up to 5 personal projects and basic task management, though features like reminders and advanced filters require a paid Pro or Business plan.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$What platforms does Todoist support?$q$, $q$Todoist is available on web, Windows, macOS, iOS, Android, and as browser extensions, with real-time sync across all devices.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$Can teams use Todoist for project management?$q$, $q$Yes, the Business plan adds shared team workspaces, task assignment, activity logs, and centralized billing, though it is better suited to lightweight team coordination than complex, multi-dependency project management.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$Does Todoist have an API for automation?$q$, $q$Yes, Todoist provides a public API and integrates with tools like Zapier, Slack, and Google Calendar for building custom workflows and automations.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$How does Todoist pricing work?$q$, $q$Todoist uses a freemium model with a free Beginner plan and paid Pro and Business tiers billed monthly or annually per user, with annual billing offering a lower effective monthly rate.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$Personal Task Management$q$, $q$Individuals organize daily to-dos, errands, and personal goals into projects with due dates and reminders.$q$, $q$Individuals and students$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$Freelance Project Tracking$q$, $q$Freelancers track client deliverables, deadlines, and recurring administrative tasks across multiple projects.$q$, $q$Freelancers and solopreneurs$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$Small Team Coordination$q$, $q$Small teams share projects, assign tasks, and track progress in a lightweight shared workspace without adopting a heavier PM tool.$q$, $q$Small businesses and startups$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$GTD-Style Productivity Systems$q$, $q$Power users build custom label and filter structures to implement methodologies like Getting Things Done across work and life.$q$, $q$Productivity enthusiasts$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$Beginner$q$, $q$Free$q$, $q$N/A$q$, $q$["5 personal projects","3 filter views","1-week activity history","Task reminders","Email and calendar integration"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$Pro$q$, $q$$5/month (billed annually) or $7/month (billed monthly)$q$, $q$Monthly or annual$q$, $q$["300 personal projects","25 collaborators per project","150 filter views","Full activity history","Automatic backups","File attachments"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$Business$q$, $q$$8/user/month (billed annually) or $10/user/month (billed monthly)$q$, $q$Monthly or annual$q$, $q$["All Pro features per member","Shared team workspace","Up to 500 team projects","Team activity logs","Shared templates","Centralized billing","Roles and permissions"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Todoist is a task and project management app built by Doist, a remote-first company founded in 2007. It has grown from a simple to-do list into one of the most widely used personal and team productivity tools, combining task lists, projects, labels, filters, and reminders into a single, clean interface available across web, desktop, and mobile.$q$, $q$The product's core appeal is its balance of simplicity and depth: a new user can add a task in seconds using natural-language quick add, while power users can build nested projects, custom filters, recurring due dates, and automation-friendly workflows through its API and integrations. Todoist syncs in real time across devices, so a task added on a phone during a commute appears instantly on a desktop or browser.$q$, $q$Todoist positions itself as a neutral, distraction-free home base for getting things done, rather than a heavyweight project management suite. It integrates with calendars, email clients, and dozens of third-party apps, making it a common choice for people who want one list to organize both work and personal life without adopting an entire team-collaboration platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$who-todoist-is-for$q$, $q$Who Todoist Is For$q$, 2, ARRAY[$q$Todoist suits individuals who want a fast, flexible personal task manager that goes beyond a basic notes app but stops short of a full project management platform. Freelancers, students, and knowledge workers who juggle multiple personal and professional to-do lists tend to find its project and label system a good match for organizing daily work.$q$, $q$Small teams and startups also use Todoist to coordinate lightweight shared projects, assign tasks, and track deadlines without the overhead of setting up a more complex tool like Asana or Jira. Its Business plan adds shared workspaces, team templates, and centralized billing, which appeals to small-to-midsize teams that want simple accountability rather than heavy reporting.$q$, $q$People who already rely on productivity methodologies such as Getting Things Done (GTD) or time-blocking often gravitate to Todoist because its filters, labels, and recurring due dates can be configured to support those systems closely, and its cross-platform reach means the same setup follows them from phone to desktop to browser.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Organizations that need robust project management features, such as Gantt charts, resource allocation, budget tracking, or complex dependency mapping, will likely outgrow Todoist quickly. It is a task manager first, and teams needing portfolio-level visibility across many concurrent projects are usually better served by tools like Asana, Monday.com, or ClickUp.$q$, $q$Teams that require deep, native integrations with enterprise software (advanced CRM, ERP, or custom internal tools) may find Todoist's integration ecosystem, while solid for common apps, thin compared to platforms built specifically for enterprise workflow automation.$q$, $q$Users who want a completely free, uncapped experience may also be frustrated: the free Beginner plan caps active projects and collaborators, and unlocking reminders, more projects, and advanced filtering requires a paid Pro or Business subscription.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Todoist offers projects, sections, and sub-tasks for structuring work, along with natural-language quick add that parses due dates, priorities, and labels as you type. Recurring due dates, reminders, and multiple view layouts (list, board, and calendar) let users adapt the same data to different working styles.$q$, $q$Collaboration features include shared projects, task assignment, comments with file attachments, and activity logs, while filters and labels provide a flexible way to slice tasks across projects by context, priority, or deadline. Templates help new users or teams get started quickly with pre-built project structures for common use cases.$q$, $q$Todoist also offers a public API, browser extensions, email and calendar forwarding, and integrations with tools such as Slack, Google Calendar, and Zapier, letting it act as a hub that pulls tasks in from other parts of a person's or team's workflow.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', $q$the-todoist-experience$q$, $q$The Todoist Experience$q$, 2, ARRAY[$q$Day-to-day, Todoist feels lightweight and fast: adding a task takes a few keystrokes, and the interface avoids the visual clutter common in larger project management tools. This simplicity is frequently cited by long-time users as the reason they stick with it over more feature-dense alternatives.$q$, $q$The mobile and desktop apps stay in sync closely, and keyboard shortcuts, quick add parsing, and karma/streak-style productivity tracking (Todoist Karma) give the app a sense of momentum that encourages consistent daily use. Widgets and quick-entry tools on mobile reduce the friction of capturing tasks in the moment.$q$, $q$For teams, the experience shifts slightly toward shared visibility: workspace-level projects, comments, and activity logs give a lightweight sense of accountability, though teams with more complex coordination needs may eventually feel the product's simplicity as a ceiling rather than a feature.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('031d68c5-af3a-4399-8fac-121f0a02a529', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
