INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('42178daa-c8ed-41d0-b8b7-d8e53057a2ce', $q$Configurable health scoring$q$, $q$Build custom health models that combine usage, support, financial, and engagement data to score account risk and opportunity.$q$, 0);
