INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('42178daa-c8ed-41d0-b8b7-d8e53057a2ce', $q$Unison AI customer intelligence$q$, $q$An AI engine that analyzes account signals to surface churn risk and expansion opportunities earlier than manual review.$q$, 3);
