INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('42178daa-c8ed-41d0-b8b7-d8e53057a2ce', $q$API access$q$, $q$Programmatic access for custom data integrations beyond the platform's native connectors.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('42178daa-c8ed-41d0-b8b7-d8e53057a2ce', $q$Enterprise security and access controls$q$, $q$SOC 2 certification, GDPR compliance, and SSO/SCIM support for enterprise identity management.$q$, 8);
