INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('42178daa-c8ed-41d0-b8b7-d8e53057a2ce', $q$AI-driven churn and expansion signals via the Unison engine$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('42178daa-c8ed-41d0-b8b7-d8e53057a2ce', $q$Executive-ready dashboards that support renewal and retention reporting$q$, 4);
