INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$On-demand video courses$q$, $q$A large catalog of instructor-led video courses covering technology, business, design, marketing, and personal development topics.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$Personal Plan subscription$q$, $q$A monthly or annual subscription giving learners access to a curated selection of the course catalog instead of paying per course.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$Udemy Business$q$, $q$A team and enterprise learning solution with curated content collections, admin controls, and reporting for organizations.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$Mobile apps$q$, $q$Native iOS and Android apps with offline downloads so learners can study lectures without an internet connection.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$Certificates of completion$q$, $q$Shareable, non-accredited certificates awarded when a learner finishes a course, useful for informal skill documentation.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$Open instructor marketplace$q$, $q$Anyone can apply to become an instructor and publish courses, set pricing guidance, and earn revenue share from sales.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$Course Q&A and discussion boards$q$, $q$Per-lecture discussion areas where students can ask instructors and peers questions about the material.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$Lifetime access to purchased courses$q$, $q$Individually purchased courses remain accessible indefinitely, including future content updates from the instructor.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$AI-powered learning tools$q$, $q$Udemy Business includes AI features such as role-play practice and personalized course recommendations for corporate learners.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$Progress tracking and notes$q$, $q$Built-in tools to track lecture completion and take timestamped notes while watching a course.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$Enormous, diverse course catalog spanning nearly every practical skill and topic$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$Frequent deep discounts make individual courses very affordable for consumers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$Lifetime access to purchased courses, including future instructor updates$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$Low barrier for instructors to publish, keeping the content library fast-growing and current$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$Udemy Business adds curated content, analytics, and admin tools for team training$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$Course quality varies significantly since instructors are not centrally vetted for teaching rigor$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$No standardized curriculum, accreditation, or quality guarantee across the catalog$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$Certificates of completion are not accredited and carry limited recognition with employers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$Personal Plan subscription pricing and course list prices can feel inflated before discounts$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$Deeply technical or highly customized corporate training needs may exceed the platform's generic catalog$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$Is Udemy free to use?$q$, $q$Udemy has a mix of free and paid content. There are some free courses available, but most of the catalog consists of paid individual courses or requires a Personal Plan subscription.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$Does Udemy offer accredited certificates?$q$, $q$No. Udemy issues certificates of completion, but they are not accredited and generally carry limited weight for professional licensing or academic credit.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$What is Udemy Business?$q$, $q$Udemy Business is a subscription product for organizations that provides a curated selection of the Udemy course catalog along with admin dashboards, reporting, and team learning management features.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$Can I get a refund on a Udemy course?$q$, $q$Udemy has historically offered a limited-time refund window on individual course purchases; specific terms should be checked on Udemy's current refund policy page, as they can change.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$What languages are Udemy courses available in?$q$, $q$Udemy's interface and course catalog support numerous languages, including English, Spanish, French, German, Portuguese, and several others, though individual course availability by language varies by instructor.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$Upskilling for a career change$q$, $q$Individuals use targeted, affordable courses to learn new technical or professional skills needed to move into a different role or industry.$q$, $q$Career changers and job seekers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$Corporate learning and development$q$, $q$Companies license Udemy Business to give employees access to a broad, curated training library alongside progress tracking and reporting.$q$, $q$HR and learning and development teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$Instructor-led course creation$q$, $q$Subject-matter experts build and publish their own courses on Udemy's marketplace to reach students and earn ongoing revenue.$q$, $q$Subject-matter experts and educators$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$Casual and lifelong learning$q$, $q$Hobbyists and lifelong learners take low-cost courses on topics of personal interest, from photography to cooking to creative writing.$q$, $q$Lifelong learners and hobbyists$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$Free Courses$q$, $q$$0$q$, $q$N/A$q$, $q$["Access to a selection of free courses","Standard course player and mobile access","No certificate guarantee on all free content"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$Individual Course Purchase$q$, $q$$9.99 - $199.99 per course (frequent discounts)$q$, $q$One-time$q$, $q$["Lifetime access to the purchased course","Certificate of completion","Downloadable resources where provided by the instructor","Access via web and mobile apps"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$Personal Plan$q$, $q$Starting around $16.99/month (varies by region and promotion)$q$, $q$Monthly or annual$q$, $q$["Unlimited access to a curated course collection","7-day free trial","Offline downloads on mobile","Cancel anytime"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$Udemy Business$q$, $q$From approximately $360/user/year (Team); custom pricing for Enterprise$q$, $q$Annual$q$, $q$["Curated business course library","Admin dashboard and reporting","AI-powered learning tools","24/7 support and custom learning paths"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Udemy is one of the world's largest online learning marketplaces, connecting learners with instructor-created video courses across technology, business, design, and personal development. Founded in 2010 by Eren Bali, Gagan Biyani, and Oktay Caglar, the platform grew from a simple idea, letting anyone teach or learn a skill online, into a marketplace with a huge catalog of courses on nearly every topic imaginable.$q$, $q$Unlike traditional e-learning providers that build in-house curricula, Udemy operates an open marketplace model: independent instructors upload courses, set or accept suggested prices, and earn a share of revenue when students purchase or stream their content. This structure has produced an enormous, constantly refreshed catalog, though it also means course quality and depth vary widely from one instructor to the next.$q$, $q$Udemy serves two very different audiences under one roof: individual consumers buying single courses or subscribing to the Personal Plan, and organizations licensing curated content through Udemy Business. Udemy has also been the subject of a proposed acquisition by Coursera announced in late 2025, a deal that would bring two well-known online education brands under one corporate umbrella while the marketplace and course catalog are expected to keep operating.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$who-udemy-is-for$q$, $q$Who Udemy Is For$q$, 2, ARRAY[$q$Udemy is best suited to self-directed learners who want to pick up a specific, practical skill quickly, such as a coding language, a design tool, a marketing tactic, office software, or exam prep, without enrolling in a formal degree program. Because courses are sold individually or through an affordable subscription, it appeals to budget-conscious learners who want to sample a topic before committing to deeper study.$q$, $q$It also works well for working professionals and career changers who need targeted, just-in-time training, since courses can typically be completed in a few hours to a few weeks and are available on-demand from any device. Aspiring instructors and subject-matter experts who want to monetize their knowledge are another core audience, since Udemy's marketplace lets anyone publish a course with minimal upfront barriers.$q$, $q$Mid-size and large organizations looking for a broad, ready-made training library rather than building custom e-learning from scratch are also well served, through Udemy Business, which curates a subset of the marketplace catalog alongside admin controls, reporting, and team analytics.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Learners who need a rigorously accredited credential, such as a university degree, a recognized professional certification, or continuing-education credit, should look elsewhere, since Udemy's certificates of completion are not accredited and carry limited weight with employers or licensing bodies compared with credentials from universities or established certification bodies.$q$, $q$Because course quality is set by individual instructors rather than a central curriculum team, learners who need guaranteed instructional rigor, cohort-based support, or mentorship should be cautious. Some courses are excellent, but others are shallow or outdated, and there is no platform-wide quality bar beyond user ratings and reviews.$q$, $q$Organizations that need deeply customized, compliance-specific, or highly technical proprietary training content may find Udemy Business's curated general catalog too generic, and would likely be better served by a bespoke corporate LMS or content built in-house.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Udemy offers on-demand video courses that students can purchase individually, stream, and revisit for as long as they retain access, typically alongside downloadable resources, quizzes, and instructor Q&A. The Personal Plan subscription extends this into a streaming-style model, giving subscribers access to a curated selection of the catalog for a flat monthly or annual fee.$q$, $q$Udemy Business layers curation, administration, and analytics on top of the same marketplace content. Team admins can assign learning paths, track completion and engagement, and combine Udemy's third-party catalog with private, organization-specific content. Recent additions include AI-assisted learning tools, such as practice role-play and course recommendations, aimed at corporate upskilling in areas like generative AI.$q$, $q$Native iOS and Android apps support offline downloads and mobile playback, while the instructor side of the platform provides course-creation tools, revenue-sharing payouts, and marketing support for anyone who wants to publish and sell their own courses.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', $q$the-udemy-experience$q$, $q$The Udemy Experience$q$, 2, ARRAY[$q$Everyday use of Udemy centers on browsing or searching a large catalog, filtering by rating, price, and topic, then watching lecture videos at your own pace with the ability to skip, rewind, or speed up playback. Frequent site-wide discounts mean list prices are rarely what most buyers actually pay for individual courses.$q$, $q$The interface is straightforward and consistent across web and mobile, with progress tracking, a note-taking feature, and a discussion area under each lecture where students can ask instructors or peers questions. Because instructors independently produce their content, production values and teaching styles differ noticeably from course to course, which is the main variable in how the experience feels day to day.$q$, $q$For teams using Udemy Business, the experience adds a management layer, including dashboards for tracking who has completed what and recommended learning paths, plus integration with existing HR or LMS systems, while individual learners largely interact with the same consumer-facing course player used on the public marketplace.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9475419b-62e2-4143-a99d-40ca73927ae3', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
