INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c49ab894-eebb-41d9-be22-6e48697bc8a4', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
